select

from stock_dividend sd
left join stock_basic sb on sd.stock_code = sb.stock_code
left join sys_dict d1 on sd.dividend_type = d1.dict_code and d1.dict_type = 'stock_dividend_type'
left join sys_dict d2 on sd.status = d2.dict_code and d2.dict_type = 'stock_dividend_status'


        AND sd.stock_code = #{stockCode}


        AND sd.year = #{year}


        AND sd.dividend_type = #{dividendType}


        AND sd.status = #{status}


        AND (sb.stock_name LIKE CONCAT('%', #{keyword}, '%')
        OR sd.stock_code LIKE CONCAT('%', #{keyword}, '%'))


order by sd.year DESC, sd.dividend_type ASC, sd.id ASC

select

from stock_dividend sd
left join stock_basic sb on sd.stock_code = sb.stock_code
left join sys_dict d1 on sd.dividend_type = d1.dict_code and d1.dict_type = 'stock_dividend_type'
left join sys_dict d2 on sd.status = d2.dict_code and d2.dict_type = 'stock_dividend_status'
where sd.stock_code = #{stockCode}
  and sd.year = #{year}
  and sd.dividend_type = #{dividendType}
limit 1

